Ini implementasi `SecureEnvManager` untuk Python. Kelas ini enforcing validasi tipe, cek permission file, dan mencegah kebocoran secrets saat debugging.

Jangan pernah mengandalkan `.env` untuk production skala besar. Gunakan Secrets Manager (AWS/GCP/Vault). Jika terpaksa pakai file, pastikan permission ketat.

```python
import os
import stat
import warnings
from pathlib import Path
from typing import Any, Optional, Dict, List
from dataclasses import dataclass

class SecurityWarning(Warning):
    pass

@dataclass
class EnvSchema:
    key: str
    type: type = str
    required: bool = True
    sensitive: bool = False
    default: Optional[Any] = None

class SecureEnvManager:
    def __init__(self, env_path: Optional[str] = ".env", schema: Optional[List[EnvSchema]] = None):
        self._data: Dict[str, str] = {}
        self._schema = schema or []
        self._sensitive_keys: set = set()

        # Load variables
        if env_path:
            self._load_secure_file(env_path)
        else:
            self._load_system_env()

        # Validate & Cast
        self._validate_schema()

    def _check_file_permissions(self, path: Path):
        """Pastikan file tidak readable oleh user lain (Unix)."""
        if os.name != 'posix':
            return

        try:
            file_stat = path.stat()
            # Cek bit 'others' read permission
            if file_stat.st_mode & stat.S_IROTH:
                raise PermissionError(
                    f"[CRITICAL] File {path} memiliki permission terlalu terbuka. "
                    f"Jalankan: chmod 600 {path}"
                )
        except FileNotFoundError:
            raise FileNotFoundError(f"File environment {path} tidak ditemukan.")

    def _load_secure_file(self, path_str: str):
        path = Path(path_str)
        self._check_file_permissions(path)

        # Parsing sederhana tanpa dependency eksternal untuk transparansi
        with path.open('r') as f:
            for line in f:
                line = line.strip()
                if not line or line.startswith('#'):
                    continue
                if '=' in line:
                    key, value = line.split('=', 1)
                    self._data[key.strip()] = value.strip().strip('"').strip("'")

    def _load_system_env(self):
        self._data = dict(os.environ)

    def _validate_schema(self):
        for field in self._schema:
            value = self._data.get(field.key)

            # Cek Required
            if field.required and value is None:
                if field.default is None:
                    raise ValueError(f"[SECURITY] Missing required env variable: {field.key}")
                value = field.default

            # Track sensitive keys
            if field.sensitive:
                self._sensitive_keys.add(field.key)

            # Type Casting
            if value is not None:
                try:
                    if field.type == bool:
                        self._data[field.key] = value.lower() in ('true', '1', 'yes')
                    else:
                        self._data[field.key] = field.type(value)
                except ValueError:
                    raise ValueError(f"[SECURITY] Type mismatch for {field.key}. Expected {field.type}")

    def get(self, key: str, default: Any = None) -> Any:
        """Ambil value. Tidak ada default untuk sensitive data."""
        value = self._data.get(key, default)

        if key in self._sensitive_keys and default is not None:
            warnings.warn(
                f"Memberikan default value untuk sensitive key '{key}' tidak disarankan.",
                SecurityWarning
            )

        return value

    def __repr__(self):
        """Mencegah leakage secrets saat print object."""
        safe_data = {
            k: "***REDACTED***" if k in self._sensitive_keys else v
            for k, v in self._data.items()
        }
        return f"SecureEnvManager({safe_data})"

    def __getitem__(self, key: str) -> Any:
        return self._data[key]
```

### Cara Penggunaan

```python
# Definisi Schema
schema = [
    EnvSchema(key="DB_PASSWORD", type=str, required=True, sensitive=True),
    EnvSchema(key="DEBUG", type=bool, required=False, default=False),
    EnvSchema(key="API_KEY", type=str, required=True, sensitive=True),
]

# Inisialisasi
try:
    env = SecureEnvManager(env_path=".env", schema=schema)
    print(env) # Output akan meredact password
except (PermissionError, ValueError) as e:
    print(f"Error: {e}")
    exit(1)
```

### Catatan Keamanan Wajib:
1.  **File Permission:** Di Linux, wajib `chmod 600 .env`. Kelas ini akan menolak load jika permission terlalu longgar.
2.  **No Default for Secrets:** Jangan pernah set default value untuk password atau API Key. Jika variabel hilang, aplikasi harus fail fast, bukan fallback ke value aman palsu.
3.  **Logging:** Pastikan logger Anda tidak mencatat object `SecureEnvManager` secara langsung tanpa filter.
4.  **Production:** Untuk production, inject variables langsung via orchestration (Docker secrets, Kubernetes Secrets, AWS Secrets Manager), jangan load dari file `.env`.
